code = """import json
import re

# Load the Swift files data using proper variable access
swift_files = locals()['var_functions.query_db:34']

# Check if it's a file path or already loaded data
if isinstance(swift_files, str) and swift_files.endswith('.json'):
    with open(swift_files, 'r') as f:
        swift_files = json.load(f)

print('Total Swift files: ' + str(len(swift_files)))

# Process files to extract copy counts
file_copy_counts = []

for file in swift_files:
    # Parse the repo_data_description to get copy count
    desc = file['repo_data_description']
    
    # Extract copy count using regex - look for patterns like "appears 9 times", "duplicated 10 times"
    match = re.search(r'(\d+)\s+times', desc)
    if match:
        copy_count = int(match.group(1))
        file_copy_counts.append({
            'id': file['id'],
            'repo_name': file['sample_repo_name'],
            'path': file['sample_path'],
            'description': desc,
            'copy_count': copy_count
        })

print('Files with extractable copy counts: ' + str(len(file_copy_counts)))

# Find file with max copies
if file_copy_counts:
    max_copies = max(f['copy_count'] for f in file_copy_counts)
    most_copied_files = [f for f in file_copy_counts if f['copy_count'] == max_copies]
    
    print('Maximum copy count: ' + str(max_copies))
    print('Number of files with max copies: ' + str(len(most_copied_files)))
    
    # Show the files with max copies
    for f in most_copied_files[:10]:  # Show first 10
        print('\nFile: ' + f['path'])
        print('Repository: ' + f['repo_name'])
        print('Copy count: ' + str(f['copy_count']))
        print('Description snippet: ' + f['description'][:100] + '...')

result = {
    'files_processed': len(file_copy_counts),
    'max_copies': max_copies if file_copy_counts else 0,
    'repo_with_max_file': most_copied_files[0]['repo_name'] if most_copied_files else None
}
print('__RESULT__:')
print(json.dumps(result))"""

